import psycopg2
from psycopg2 import sql
import sys

def connect_to_db(host, database, user, password, port=5432):
    try:
        connection = psycopg2.connect(
            host=host,
            database=database,
            user=user,
            password=password,
            port=port
        )
        return connection
    except Exception as e:
        print(f"Error connecting to database: {e}")
        sys.exit(1)

def install_extension(connection, extension_name):
    try:
        cursor = connection.cursor()
        create_extension_query = sql.SQL("CREATE EXTENSION IF NOT EXISTS {}").format(
            sql.Identifier(extension_name)
        )
        cursor.execute(create_extension_query)
        connection.commit()
        cursor.close()
        print(f"Extension '{extension_name}' installed successfully.")
    except Exception as e:
        print(f"Error installing extension '{extension_name}': {e}")
        connection.rollback()

def main():
    # Database connection parameters
    db_config = {
        'host': 'localhost',
        'database': 'your_database',
        'user': 'your_username',
        'password': 'your_password',
        'port': 5432
    }
    
    connection = connect_to_db(**db_config)
    
    print("PostgreSQL Extension Installer")
    print("Enter extension names (type 'quit' to exit):")
    
    while True:
        extension_name = input("Extension name: ").strip()
        
        if extension_name.lower() == 'quit':
            break
            
        if extension_name:
            install_extension(connection, extension_name)
    
    connection.close()
    print("Connection closed.")

if __name__ == "__main__":
    main()